import UIKit
import SwiftUI

@main
struct PromoLinkApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    
    var body: some Scene {
        WindowGroup {
            ContentView()
                .onOpenURL { url in
                    PromoLinkHandler.shared.handlePromoLink(url)
                }
        }
    }
}

class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        PromoLinkHandler.shared.handlePromoLink(url)
        return true
    }
    
    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        PromoLinkHandler.shared.handlePromoLink(url)
        return true
    }
}

struct PromoCode: Codable, Identifiable {
    let id: UUID
    let code: String
    let discount: Int
    let appliedDate: Date
    
    init(code: String, discount: Int) {
        self.id = UUID()
        self.code = code
        self.discount = discount
        self.appliedDate = Date()
    }
}

class UserAccount: ObservableObject {
    @Published var appliedPromoCodes: [PromoCode] = []
    @Published var currentDiscount: Int = 0
    
    static let shared = UserAccount()
    
    private let userDefaults = UserDefaults.standard
    private let promoCodesKey = "appliedPromoCodes"
    
    private init() {
        loadPromoCodes()
        calculateCurrentDiscount()
    }
    
    func applyPromoCode(_ promoCode: PromoCode) {
        if !appliedPromoCodes.contains(where: { $0.code == promoCode.code }) {
            appliedPromoCodes.append(promoCode)
            savePromoCodes()
            calculateCurrentDiscount()
        }
    }
    
    private func calculateCurrentDiscount() {
        currentDiscount = appliedPromoCodes.map { $0.discount }.max() ?? 0
    }
    
    private func savePromoCodes() {
        if let encoded = try? JSONEncoder().encode(appliedPromoCodes) {
            userDefaults.set(encoded, forKey: promoCodesKey)
        }
    }
    
    private func loadPromoCodes() {
        if let data = userDefaults.data(forKey: promoCodesKey),
           let decoded = try? JSONDecoder().decode([PromoCode].self, from: data) {
            appliedPromoCodes = decoded
        }
    }
    
    func removePromoCode(_ promoCode: PromoCode) {
        appliedPromoCodes.removeAll { $0.id == promoCode.id }
        savePromoCodes()
        calculateCurrentDiscount()
    }
    
    func clearAllPromoCodes() {
        appliedPromoCodes.removeAll()
        savePromoCodes()
        calculateCurrentDiscount()
    }
}

class PromoLinkHandler: ObservableObject {
    static let shared = PromoLinkHandler()
    
    @Published var lastPromoCode: PromoCode?
    @Published var showPromoAlert = false
    @Published var alertMessage = ""
    
    private init() {}
    
    func handlePromoLink(_ url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return
        }
        
        guard components.host == "myapp.com" || components.host == "www.myapp.com" else {
            return
        }
        
        guard components.path == "/promo" else {
            return
        }
        
        guard let queryItems = components.queryItems else {
            return
        }
        
        var code: String?
        var discount: Int?
        
        for item in queryItems {
            if item.name == "code" {
                code = item.value
            } else if item.name == "discount" {
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            }
        }
        
        guard let promoCode = code, let discountValue = discount else {
            DispatchQueue.main.async {
                self.alertMessage = "Invalid promo link. Missing code or discount."
                self.showPromoAlert = true
            }
            return
        }
        
        guard discountValue >= 0 && discountValue <= 100 else {
            DispatchQueue.main.async {
                self.alertMessage = "Invalid discount percentage. Must be between 0 and 100."
                self.showPromoAlert = true
            }
            return
        }
        
        let promo = PromoCode(code: promoCode, discount: discountValue)
        
        DispatchQueue.main.async {
            UserAccount.shared.applyPromoCode(promo)
            self.lastPromoCode = promo
            self.alertMessage = "Promo code '\(promoCode)' applied! You get \(discountValue)% off."
            self.showPromoAlert = true
        }
    }
}

